3_real_world_example.code:
function announce() {
  console.log('SkillSprint session starting!');
}

//  Reference — passes the function, runs it after 2 seconds
setTimeout(announce, 2000);

//  Accidental call — runs immediately AND passes return value (undefined) to setTimeout
setTimeout(announce(), 2000); // calls announce() RIGHT NOW

// Method invocation — 'this' is bound to the object
const session = {
  name: 'JS Fundamentals',
  start() {
    console.log(`Starting: ${this.name}`);
  }
};
session.start(); // 'this' === session

6_edge_case.code:
// IIFE: defined and invoked in one shot
const result = (function(multiplier) {
  return 42 * multiplier;
})(3);

console.log(result); // 126
// The function body ran once and the function object is immediately discarded
